tool.command:
mkdir out ; 

## Rename all input files to correct extensions
mv "$scan" "$scan.element_identifier" ;  
mv "$predicted" "$predicted.element_identifier" ; 
mv "$found" "$found.element_identifier" ; 

python -m subhkl.io.parser integrator "$scan.element_identifier" $instrument "$predicted.element_identifier" out/integrator.h5 --integration-method $method --found-peaks-file $found --region-growth-minimum-sigma $sigma --region-growth-maximum-pixel-radius $radius --peak-center-box-size $boxSize --peak-smoothing-window-size $windowSize --peak-minimum-pixels $pixels --peak-minimum-signal-to-noise $signal --peak-pixel-outlier-threshold $threshold --create-visualizations --show-progress ;
